                  onClick={() => document.getElementById('kyc-file-input')?.click()}
                >
                  <Upload className="w-8 h-8 mx-auto mb-2 text-muted-foreground" />
                  <p className="text-sm text-muted-foreground">
                    Click to upload documents (JPG, PNG, PDF - max 5MB each)
                  </p>
                  <input
                    id="kyc-file-input"
                    type="file"
                    multiple
                    accept=".jpg,.jpeg,.png,.pdf"
                    className="hidden"
                    onChange={handleFileChange}
                    data-testid="input-kyc-files"
                  />
                </div>
              </div>

              {kycFiles.length > 0 && (
                <div className="space-y-2">
                  <Label>Selected Documents ({kycFiles.length})</Label>
                  <div className="space-y-2">
                    {kycFiles.map((file, index) => (
                      <div 
                        key={index} 
                        className="flex items-center justify-between p-3 bg-secondary/50 rounded-lg"
                      >
                        <div className="flex items-center gap-2">
                          <FileText className="w-4 h-4 text-muted-foreground" />
                          <span className="text-sm truncate max-w-[200px]">{file.name}</span>
                          <span className="text-xs text-muted-foreground">
                            ({(file.size / 1024).toFixed(1)} KB)
                          </span>
                        </div>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeFile(index)}
                          data-testid={`button-remove-file-${index}`}
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div className="flex justify-end gap-3 pt-4">
                <Button 
                  variant="outline" 
                  onClick={() => {
                    setIsKycDialogOpen(false);
                    setKycFiles([]);
                    setBusinessAddress("");
                    setGstNumber("");
                  }}
                >
                  Cancel
                </Button>
                <Button 
                  onClick={handleKycSubmit}
                  disabled={
                    kycUploading || 
                    kycFiles.length === 0 || 
                    !gstValidationResult.valid || 
                    !addressValidationResult.valid
                  }
                  data-testid="button-submit-kyc"
                >
                  {kycUploading ? (
                    <span className="flex items-center gap-2">
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Submitting...
                    </span>
                  ) : (
