import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  CheckCircle,
  XCircle,
  Ban,
  CheckCheck,
  Package,
  DollarSign,
  Star,
  ShoppingBag,
  FileText,
  Building,
  Mail,
  Phone,
  MapPin,
} from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Vendor, Product } from "@shared/schema";
import { useToast } from "@/hooks/use-toast";

interface VendorManagementDialogProps {
  vendor: Vendor | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

interface VendorStats {
  totalProducts: number;
  activeOrders: number;
  totalRevenue: number;
  avgRating: number;
}

export function VendorManagementDialog({
  vendor,
  open,
  onOpenChange,
}: VendorManagementDialogProps) {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("info");

  const { data: vendorProducts = [], isLoading: productsLoading } = useQuery<Product[]>({
    queryKey: ["/api/vendors", vendor?.id, "products"],
    enabled: !!vendor?.id && open,
  });

  const { data: vendorStats, isLoading: statsLoading } = useQuery<VendorStats>({
    queryKey: ["/api/vendors", vendor?.id, "stats"],
    enabled: !!vendor?.id && open,
  });

  const approveMutation = useMutation({
    mutationFn: (vendorId: string) =>
      apiRequest("POST", `/api/vendors/${vendorId}/approve`, {}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/vendors"] });
      toast({
        title: "Vendor Approved",
        description: "Vendor KYC has been approved successfully",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to approve vendor",
        variant: "destructive",
      });
    },
  });

  const rejectMutation = useMutation({
    mutationFn: (vendorId: string) =>
      apiRequest("POST", `/api/vendors/${vendorId}/reject`, {}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/vendors"] });
      toast({
        title: "Vendor Rejected",
        description: "Vendor KYC has been rejected",
        variant: "destructive",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to reject vendor",
        variant: "destructive",
      });
    },
  });

  const suspendMutation = useMutation({
    mutationFn: (vendorId: string) =>
      apiRequest("POST", `/api/vendors/${vendorId}/suspend`, {}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/vendors"] });
      toast({
        title: "Vendor Suspended",
        description: "Vendor account has been suspended",
        variant: "destructive",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to suspend vendor",
        variant: "destructive",
      });
    },
  });

  const activateMutation = useMutation({
    mutationFn: (vendorId: string) =>
      apiRequest("POST", `/api/vendors/${vendorId}/activate`, {}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/vendors"] });
      toast({
        title: "Vendor Activated",
        description: "Vendor account has been activated",
      });
      onOpenChange(false);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to activate vendor",
        variant: "destructive",
      });
    },
  });

  const handleApprove = () => {
    if (vendor) {
      approveMutation.mutate(vendor.id);
    }
  };

  const handleReject = () => {
    if (vendor) {
      rejectMutation.mutate(vendor.id);
    }
  };

  const handleSuspend = () => {
    if (vendor) {
      suspendMutation.mutate(vendor.id);
    }
  };

  const handleActivate = () => {
    if (vendor) {
      activateMutation.mutate(vendor.id);
    }
  };

  const getKycBadge = (status: string) => {
    const variants: Record<string, { className: string; label: string }> = {
      approved: { className: "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300", label: "Approved" },
      pending: { className: "bg-yellow-100 text-yellow-700 dark:bg-yellow-900 dark:text-yellow-300", label: "Pending" },
      rejected: { className: "bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300", label: "Rejected" },
    };
    const variant = variants[status] || { className: "", label: status };
    return <Badge className={variant.className}>{variant.label}</Badge>;
  };

  const getActiveBadge = (isActive: boolean) => {
    return isActive ? (
      <Badge className="bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300">Active</Badge>
    ) : (
      <Badge className="bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300">Suspended</Badge>
    );
  };

  if (!vendor) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto" data-testid="dialog-vendor-management">
        <DialogHeader>
          <DialogTitle className="text-2xl font-serif" data-testid="text-vendor-name">
            {vendor.businessName}
          </DialogTitle>
          <DialogDescription>
            Complete vendor profile and management controls
          </DialogDescription>
        </DialogHeader>

        <div className="flex gap-3 mb-4">
          {getKycBadge(vendor.kycStatus)}
          {getActiveBadge(vendor.isActive ?? true)}
        </div>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="info" data-testid="tab-info">Info</TabsTrigger>
            <TabsTrigger value="documents" data-testid="tab-documents">Documents</TabsTrigger>
            <TabsTrigger value="products" data-testid="tab-products">Products</TabsTrigger>
            <TabsTrigger value="stats" data-testid="tab-stats">Stats</TabsTrigger>
          </TabsList>

          <TabsContent value="info" className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-3">
                <div className="flex items-start gap-3">
                  <Building className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">Business Name</p>
                    <p className="font-medium" data-testid="text-business-name">{vendor.businessName}</p>
                  </div>
                </div>

                <div className="flex items-start gap-3">
                  <FileText className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">GST Number</p>
                    <p className="font-medium" data-testid="text-gst-number">{vendor.gstNumber || "Not provided"}</p>
                  </div>
                </div>

                <div className="flex items-start gap-3">
                  <MapPin className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">Business Address</p>
                    <p className="font-medium" data-testid="text-business-address">{vendor.businessAddress || "Not provided"}</p>
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-start gap-3">
                  <Star className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">Rating</p>
                    <p className="font-medium" data-testid="text-rating">
                      {Number(vendor.rating).toFixed(2)} ⭐
                    </p>
                  </div>
                </div>

                <div className="flex items-start gap-3">
                  <DollarSign className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">Total Sales</p>
                    <p className="font-medium" data-testid="text-total-sales">{vendor.totalSales || 0}</p>
                  </div>
                </div>

                <div className="flex items-start gap-3">
                  <Package className="w-5 h-5 text-muted-foreground mt-1" />
                  <div>
                    <p className="text-sm text-muted-foreground">Description</p>
                    <p className="font-medium text-sm" data-testid="text-description">
                      {vendor.description || "No description available"}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="documents" className="space-y-4">
            <div>
              <h3 className="font-semibold mb-3">KYC Documents</h3>
              {vendor.kycDocuments && Array.isArray(vendor.kycDocuments) && vendor.kycDocuments.length > 0 ? (
                <div className="space-y-2">
                  {vendor.kycDocuments.map((doc: any, index: number) => (
                    <div
                      key={index}
                      className="flex items-center justify-between p-3 border rounded-md"
                      data-testid={`doc-${index}`}
                    >
                      <div className="flex items-center gap-2">
                        <FileText className="w-4 h-4 text-muted-foreground" />
                        <span className="text-sm">{doc.name || `Document ${index + 1}`}</span>
                      </div>
                      {doc.url && (
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => window.open(doc.url, "_blank")}
                          data-testid={`button-view-doc-${index}`}
                        >
                          View
                        </Button>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-muted-foreground text-sm py-4" data-testid="text-no-documents">
                  No KYC documents uploaded yet
                </p>
              )}
            </div>
          </TabsContent>

          <TabsContent value="products" className="space-y-4">
            {productsLoading ? (
              <div className="py-8 text-center text-muted-foreground">Loading products...</div>
            ) : vendorProducts.length === 0 ? (
              <div className="py-8 text-center text-muted-foreground" data-testid="text-no-products">
                No products found for this vendor
              </div>
            ) : (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Product Name</TableHead>
                      <TableHead>Price</TableHead>
                      <TableHead>Stock</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {vendorProducts.map((product) => (
                      <TableRow key={product.id} data-testid={`row-product-${product.id}`}>
                        <TableCell className="font-medium" data-testid={`text-product-name-${product.id}`}>
                          {product.name}
                        </TableCell>
                        <TableCell data-testid={`text-product-price-${product.id}`}>
                          ₹{Number(product.price).toLocaleString()}
                        </TableCell>
                        <TableCell data-testid={`text-product-stock-${product.id}`}>
                          {product.stock}
                        </TableCell>
                        <TableCell>
                          {product.isActive ? (
                            <Badge className="bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300">
                              Active
                            </Badge>
                          ) : (
                            <Badge className="bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300">
                              Inactive
                            </Badge>
                          )}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </TabsContent>

          <TabsContent value="stats" className="space-y-4">
            {statsLoading ? (
              <div className="py-8 text-center text-muted-foreground">Loading stats...</div>
            ) : (
              <div className="grid grid-cols-2 gap-4">
                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-sm font-medium text-muted-foreground">
                      Total Products
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center gap-2">
                      <Package className="w-5 h-5 text-blue-600" />
                      <span className="text-2xl font-serif font-semibold" data-testid="text-stat-products">
                        {vendorStats?.totalProducts || 0}
                      </span>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-sm font-medium text-muted-foreground">
                      Active Orders
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center gap-2">
                      <ShoppingBag className="w-5 h-5 text-green-600" />
                      <span className="text-2xl font-serif font-semibold" data-testid="text-stat-orders">
                        {vendorStats?.activeOrders || 0}
                      </span>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-sm font-medium text-muted-foreground">
                      Total Revenue
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center gap-2">
                      <DollarSign className="w-5 h-5 text-purple-600" />
                      <span className="text-2xl font-serif font-semibold" data-testid="text-stat-revenue">
                        ₹{vendorStats?.totalRevenue?.toLocaleString() || 0}
                      </span>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-3">
                    <CardTitle className="text-sm font-medium text-muted-foreground">
                      Average Rating
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center gap-2">
                      <Star className="w-5 h-5 text-yellow-600" />
                      <span className="text-2xl font-serif font-semibold" data-testid="text-stat-rating">
                        {vendorStats?.avgRating?.toFixed(2) || "0.00"}
                      </span>
                    </div>
                  </CardContent>
                </Card>
              </div>
            )}
          </TabsContent>
        </Tabs>

        <div className="flex gap-2 pt-4 border-t">
          {vendor.kycStatus === "pending" && (
            <>
              <Button
                onClick={handleApprove}
                disabled={approveMutation.isPending}
                data-testid="button-approve-vendor"
              >
                <CheckCircle className="w-4 h-4 mr-2" />
                {approveMutation.isPending ? "Approving..." : "Approve"}
              </Button>
              <Button
                variant="destructive"
                onClick={handleReject}
                disabled={rejectMutation.isPending}
                data-testid="button-reject-vendor"
              >
                <XCircle className="w-4 h-4 mr-2" />
                {rejectMutation.isPending ? "Rejecting..." : "Reject"}
              </Button>
            </>
          )}

          {vendor.kycStatus === "approved" && (
            <>
              {vendor.isActive ? (
                <Button
                  variant="destructive"
                  onClick={handleSuspend}
                  disabled={suspendMutation.isPending}
                  data-testid="button-suspend-vendor"
                >
                  <Ban className="w-4 h-4 mr-2" />
                  {suspendMutation.isPending ? "Suspending..." : "Suspend"}
                </Button>
              ) : (
                <Button
                  onClick={handleActivate}
                  disabled={activateMutation.isPending}
                  data-testid="button-activate-vendor"
                >
                  <CheckCheck className="w-4 h-4 mr-2" />
                  {activateMutation.isPending ? "Activating..." : "Activate"}
                </Button>
              )}
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/pages/AdminProducts.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useToast } from "@/hooks/use-toast";
import { Package, Search, Upload, ArrowLeft, Trash2, Edit, CheckCircle, XCircle, Eye } from "lucide-react";
import type { Product, Category, Vendor } from "@shared/schema";

export default function AdminProducts() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [categoryFilter, setCategoryFilter] = useState<string>("all");
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [viewDialogOpen, setViewDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [productToDelete, setProductToDelete] = useState<string | null>(null);

  const { data: products = [], isLoading, refetch } = useQuery<Product[]>({
    queryKey: ["/api/admin/products", { status: statusFilter !== "all" ? statusFilter : undefined, search: search || undefined }],
  });

  const { data: categories = [] } = useQuery<Category[]>({
    queryKey: ["/api/categories"],
  });

  const { data: vendors = [] } = useQuery<Vendor[]>({
    queryKey: ["/api/vendors"],
  });

  const approveProductMutation = useMutation({
    mutationFn: async (productId: string) => {
      return await apiRequest("POST", `/api/admin/products/${productId}/approve`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/products"] });
      toast({
        title: "Product Approved",
        description: "Product has been approved successfully",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to approve product",
        variant: "destructive",
      });
    },
  });

  const publishProductMutation = useMutation({
    mutationFn: async (productId: string) => {
      return await apiRequest("POST", `/api/admin/products/${productId}/publish`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/products"] });
      toast({
        title: "Product Published",
        description: "Product has been published successfully",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to publish product",
        variant: "destructive",
      });
    },
  });

  const deleteProductMutation = useMutation({
    mutationFn: async (productId: string) => {
      return await apiRequest("DELETE", `/api/admin/products/${productId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/products"] });
      toast({
        title: "Product Deleted",
        description: "Product has been deleted successfully",
      });
      setDeleteDialogOpen(false);
      setProductToDelete(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete product",
        variant: "destructive",
      });
    },
  });

  const filteredProducts = products.filter(product => {
    const matchesCategory = categoryFilter === "all" || product.categoryId === categoryFilter;
    return matchesCategory;
  });

  const getStatusBadge = (status: string) => {
    const variants: Record<string, { className: string; label: string }> = {
      pending: { className: "bg-yellow-100 text-yellow-700 dark:bg-yellow-900 dark:text-yellow-300", label: "Pending" },
      approved: { className: "bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300", label: "Approved" },
      published: { className: "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300", label: "Published" },
    };
    const variant = variants[status] || { className: "", label: status };
    return <Badge className={variant.className}>{variant.label}</Badge>;
  };

  const handleViewProduct = (product: Product) => {
    setSelectedProduct(product);
    setViewDialogOpen(true);
  };

  const handleDeleteClick = (productId: string) => {
    setProductToDelete(productId);
    setDeleteDialogOpen(true);
  };

  const handleConfirmDelete = () => {
    if (productToDelete) {
      deleteProductMutation.mutate(productToDelete);
    }
  };

  const getVendorName = (vendorId: string) => {
    const vendor = vendors.find(v => v.id === vendorId);
    return vendor?.businessName || "Unknown";
  };

  const getCategoryName = (categoryId: string | null) => {
    if (!categoryId) return "Uncategorized";
    const category = categories.find(c => c.id === categoryId);
    return category?.name || "Unknown";
  };

  return (
    <div className="min-h-screen py-8">
      <div className="container mx-auto px-6">
        <div className="mb-8">
          <Button 
            variant="ghost" 
            onClick={() => setLocation("/dashboard/admin")}
            className="mb-4"
            data-testid="button-back"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Dashboard
          </Button>
          <div className="flex items-center justify-between">
            <div>
              <h1 className="font-serif text-4xl font-semibold mb-2" data-testid="text-title">
                Product Management
              </h1>
              <p className="text-muted-foreground">
                Manage and approve products from vendors
              </p>
            </div>
            <Button
              onClick={() => setLocation("/dashboard/admin/products/bulk-upload")}
              data-testid="button-bulk-upload"
            >
              <Upload className="w-4 h-4 mr-2" />
              Bulk Upload
            </Button>
          </div>
        </div>

        <Card className="mb-6">
          <CardHeader>
            <CardTitle>Filters</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Search Products</Label>
                <div className="relative">
                  <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Search by name or description..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-10"
                    data-testid="input-search"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label>Status</Label>
                <Select value={statusFilter} onValueChange={setStatusFilter}>
                  <SelectTrigger data-testid="select-status">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Status</SelectItem>
                    <SelectItem value="pending">Pending</SelectItem>
                    <SelectItem value="approved">Approved</SelectItem>
                    <SelectItem value="published">Published</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Category</Label>
                <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                  <SelectTrigger data-testid="select-category">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Categories</SelectItem>
                    {categories.map((category) => (
                      <SelectItem key={category.id} value={category.id}>
                        {category.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Products ({filteredProducts.length})</CardTitle>
            <CardDescription>Review and manage all products in the platform</CardDescription>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="py-8 text-center text-muted-foreground">Loading products...</div>
            ) : filteredProducts.length === 0 ? (
              <div className="py-8 text-center text-muted-foreground">
                <Package className="w-12 h-12 mx-auto mb-4 opacity-50" />
                <p>No products found matching your filters.</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Product Name</TableHead>
                      <TableHead>Vendor</TableHead>
                      <TableHead>Category</TableHead>
                      <TableHead>Price</TableHead>
                      <TableHead>Stock</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredProducts.map((product) => (
                      <TableRow key={product.id} data-testid={`row-product-${product.id}`}>
                        <TableCell className="font-medium" data-testid={`text-product-name-${product.id}`}>
                          {product.name}
                        </TableCell>
                        <TableCell>{getVendorName(product.vendorId)}</TableCell>
                        <TableCell>{getCategoryName(product.categoryId)}</TableCell>
                        <TableCell>₹{Number(product.price).toLocaleString()}</TableCell>
                        <TableCell>
                          <span className={product.stock < 10 ? "text-orange-600" : ""}>
                            {product.stock}
                          </span>
                        </TableCell>
                        <TableCell>{getStatusBadge(product.status)}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleViewProduct(product)}
                              data-testid={`button-view-${product.id}`}
                            >
                              <Eye className="w-4 h-4" />
                            </Button>
                            {product.status === "pending" && (
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => approveProductMutation.mutate(product.id)}
                                disabled={approveProductMutation.isPending}
                                data-testid={`button-approve-${product.id}`}
                              >
                                <CheckCircle className="w-4 h-4 text-green-600" />
                              </Button>
                            )}
                            {product.status === "approved" && (
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => publishProductMutation.mutate(product.id)}
                                disabled={publishProductMutation.isPending}
                                data-testid={`button-publish-${product.id}`}
                              >
                                <CheckCircle className="w-4 h-4 text-blue-600" />
                              </Button>
                            )}
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleDeleteClick(product.id)}
                              data-testid={`button-delete-${product.id}`}
                            >
                              <Trash2 className="w-4 h-4 text-red-600" />
                            </Button>
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <Dialog open={viewDialogOpen} onOpenChange={setViewDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Product Details</DialogTitle>
            <DialogDescription>View full product information</DialogDescription>
          </DialogHeader>
          {selectedProduct && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-muted-foreground">Product Name</Label>
                  <p className="font-medium">{selectedProduct.name}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Status</Label>
                  <div className="mt-1">{getStatusBadge(selectedProduct.status)}</div>
                </div>
                <div>
                  <Label className="text-muted-foreground">Vendor</Label>
                  <p className="font-medium">{getVendorName(selectedProduct.vendorId)}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Category</Label>
                  <p className="font-medium">{getCategoryName(selectedProduct.categoryId)}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Price</Label>
                  <p className="font-medium">₹{Number(selectedProduct.price).toLocaleString()}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Stock</Label>
                  <p className="font-medium">{selectedProduct.stock}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">MOQ</Label>
                  <p className="font-medium">{selectedProduct.moq}</p>
                </div>
                <div>
                  <Label className="text-muted-foreground">Fabric</Label>
                  <p className="font-medium">{selectedProduct.fabric || "N/A"}</p>
                </div>
              </div>
              <div>
                <Label className="text-muted-foreground">Description</Label>
                <p className="mt-1">{selectedProduct.description}</p>
              </div>
              {selectedProduct.images && Array.isArray(selectedProduct.images) && selectedProduct.images.length > 0 && (
                <div>
                  <Label className="text-muted-foreground">Images</Label>
                  <div className="grid grid-cols-4 gap-2 mt-2">
                    {(selectedProduct.images as string[]).map((image, idx) => (
                      <img
                        key={idx}
                        src={image}
                        alt={`Product ${idx + 1}`}
                        className="w-full h-20 object-cover rounded"
                      />
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Product</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this product? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel data-testid="button-cancel-delete">Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              data-testid="button-confirm-delete"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

client/src/pages/AdminProductsBulkUpload.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { useToast } from "@/hooks/use-toast";
import { ArrowLeft, Upload, FileText, Download, AlertCircle } from "lucide-react";

export default function AdminProductsBulkUpload() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadResult, setUploadResult] = useState<{
    created?: number;
    errors?: Array<{ row: number; error: string }>;
  } | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setUploadResult(null);
    }
  };

  const handleUpload = async () => {
    if (!file) {
      toast({
        title: "No File Selected",
        description: "Please select a CSV file to upload",
        variant: "destructive",
      });
      return;
    }

    setUploading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const token = localStorage.getItem("adminToken");
      const response = await fetch("/api/admin/products/bulk-upload", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${token}`,
        },
        body: formData,
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Upload failed");
      }

      setUploadResult({
        created: data.created,
        errors: data.errors,
      });

      toast({
        title: "Upload Successful",
        description: `Successfully uploaded ${data.created} products`,
      });

      setFile(null);
      const fileInput = document.querySelector('input[type="file"]') as HTMLInputElement;
      if (fileInput) fileInput.value = '';
    } catch (error: any) {
      toast({
        title: "Upload Failed",
        description: error.message || "Failed to upload products",
        variant: "destructive",
      });
    } finally {
      setUploading(false);
    }
  };

  const downloadSampleCSV = () => {
    const sampleData = `vendorId,name,description,categoryId,fabric,price,moq,stock,images,colors,sizes,bulkPricing
vendor-id-here,Sample Cotton T-Shirt,High quality cotton t-shirt for wholesale,category-id-here,Cotton,299,10,100,"[""https://example.com/image1.jpg""]","[""White"",""Black"",""Blue""]","[""S"",""M"",""L"",""XL""]","[{""quantity"":50,""price"":280},{""quantity"":100,""price"":250}]"`;

    const blob = new Blob([sampleData], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "sample-products.csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen py-8">
      <div className="container mx-auto px-6 max-w-4xl">
        <div className="mb-8">
          <Button 
            variant="ghost" 
            onClick={() => setLocation("/dashboard/admin/products")}
            className="mb-4"
            data-testid="button-back"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Products
          </Button>
          <div>
            <h1 className="font-serif text-4xl font-semibold mb-2" data-testid="text-title">
              Bulk Upload Products
            </h1>
            <p className="text-muted-foreground">
              Upload multiple products at once using a CSV or Excel file
            </p>
          </div>
        </div>

        <Card className="mb-6">
          <CardHeader>
            <CardTitle>Instructions</CardTitle>
            <CardDescription>Follow these steps to bulk upload products</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <h3 className="font-semibold">Required Fields:</h3>
              <ul className="list-disc list-inside space-y-1 text-sm text-muted-foreground">
                <li><strong>vendorId</strong> - The ID of the vendor (required)</li>
                <li><strong>name</strong> - Product name (required)</li>
                <li><strong>description</strong> - Product description (required)</li>
                <li><strong>price</strong> - Product price (required)</li>
              </ul>
            </div>
            <div className="space-y-2">
              <h3 className="font-semibold">Optional Fields:</h3>
              <ul className="list-disc list-inside space-y-1 text-sm text-muted-foreground">
                <li><strong>categoryId</strong> - Category ID</li>
                <li><strong>fabric</strong> - Fabric type</li>
                <li><strong>moq</strong> - Minimum order quantity (default: 10)</li>
                <li><strong>stock</strong> - Available stock (default: 0)</li>
                <li><strong>images</strong> - JSON array of image URLs</li>
                <li><strong>colors</strong> - JSON array of colors</li>
                <li><strong>sizes</strong> - JSON array of sizes</li>
                <li><strong>bulkPricing</strong> - JSON array of pricing tiers</li>
              </ul>
            </div>
            <Alert>
              <FileText className="h-4 w-4" />
              <AlertTitle>Sample CSV Template</AlertTitle>
              <AlertDescription>
                <p className="mb-2">Download a sample CSV template with the correct format</p>
                <Button 
                  size="sm" 
                  variant="outline" 
                  onClick={downloadSampleCSV}
                  data-testid="button-download-sample"
                >
                  <Download className="w-4 h-4 mr-2" />
                  Download Sample CSV
                </Button>
              </AlertDescription>
            </Alert>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Upload File</CardTitle>
            <CardDescription>Select a CSV or Excel file to upload</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="file-upload">Select File</Label>
              <Input
                id="file-upload"
                type="file"
                accept=".csv,.xlsx,.xls"
                onChange={handleFileChange}
                disabled={uploading}
                data-testid="input-file"
              />
              {file && (
                <p className="text-sm text-muted-foreground">
                  Selected: {file.name} ({(file.size / 1024).toFixed(2)} KB)
                </p>
              )}
            </div>

            <Button
              onClick={handleUpload}
              disabled={!file || uploading}
              className="w-full"
              data-testid="button-upload"
            >
              <Upload className="w-4 h-4 mr-2" />
              {uploading ? "Uploading..." : "Upload Products"}
            </Button>

            {uploadResult && (
              <div className="space-y-4 mt-6">
                {uploadResult.created > 0 && (
                  <Alert className="border-green-200 bg-green-50 dark:border-green-900 dark:bg-green-950">
                    <AlertCircle className="h-4 w-4 text-green-600" />
                    <AlertTitle className="text-green-900 dark:text-green-100">Upload Successful</AlertTitle>
                    <AlertDescription className="text-green-800 dark:text-green-200">
                      Successfully uploaded {uploadResult.created} products. All products are in "Pending" status and need to be approved before publishing.
                    </AlertDescription>
                  </Alert>
                )}

                {uploadResult.errors && uploadResult.errors.length > 0 && (
                  <Alert variant="destructive">
                    <AlertCircle className="h-4 w-4" />
                    <AlertTitle>Errors Found</AlertTitle>
                    <AlertDescription>
                      <p className="mb-2">The following rows had errors:</p>
                      <ul className="list-disc list-inside space-y-1 text-sm">
                        {uploadResult.errors.map((error, idx) => (
                          <li key={idx}>
                            Row {error.row}: {error.error}
                          </li>
                        ))}
                      </ul>
                    </AlertDescription>
                  </Alert>
                )}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

