      onClick={toggleTheme}
      className="text-gray-600 hover:text-primary dark:text-gray-300 dark:hover:text-primary"
      data-testid="button-theme-toggle"
    >
      {theme === "light" ? (
        <Moon className="w-5 h-5" />
      ) : (
        <Sun className="w-5 h-5" />
      )}
    </Button>
  );
}

